async def add_ball_on_patch():
    objs = await get_all_objects()
    patch = next((o for o in objs['objects'] if 'patch' in o['name'] or 'box' in o['name']), None)
    if patch:
        pos = patch['position']
        return await add_object(name='ball', x=pos[0], y=pos[1], z=pos[2] + 0.04, shape='sphere', color='red', size=0.02)
    return {'success': False}
